// Calculate date ranges for the past 7 days
const now = new Date();

// End of range: now
const toDateTime = now.toISOString();

// Start of range: 7 days ago
const fromDate = new Date(now);
fromDate.setDate(fromDate.getDate() - 7);
const fromDateTime = fromDate.toISOString();

// For the output filename
const reportDate = now.toISOString().split('T')[0]; // YYYY-MM-DD
const dateRangeLabel = `${fromDate.toLocaleDateString('en-US', {month: 'short', day: 'numeric'})} - ${now.toLocaleDateString('en-US', {month: 'short', day: 'numeric', year: 'numeric'})}`;

return [{
  json: {
    fromDateTime,
    toDateTime,
    reportDate,
    dateRangeLabel
  }
}];

// Extract call IDs and basic metadata from Gong response
// Filter out very short calls (< 2 min) as likely connection tests
const response = $input.first().json;
const dateRanges = $node['Calculate Date Ranges'].json;

const calls = response.records?.calls || response.calls || [];

// Filter out calls shorter than 2 minutes (120 seconds)
const validCalls = calls.filter(call => {
  const duration = call.duration || call.actualDuration || 0;
  return duration >= 120;
});

// Extract call IDs for the extensive endpoint
const callIds = validCalls.map(call => call.id);

// Store basic metadata keyed by call ID
const callMetadata = {};
validCalls.forEach(call => {
  callMetadata[call.id] = {
    title: call.title || 'Untitled Call',
    started: call.started,
    duration: call.duration || call.actualDuration || 0,
    durationMinutes: Math.round((call.duration || call.actualDuration || 0) / 60),
    direction: call.direction,
    url: call.url || ''
  };
});

return [{
  json: {
    callIds,
    callMetadata,
    totalCalls: validCalls.length,
    reportDate: dateRanges.reportDate,
    dateRangeLabel: dateRanges.dateRangeLabel
  }
}];

// Split call IDs into batches of 20 for the extensive endpoint
const { callIds, callMetadata, totalCalls, reportDate, dateRangeLabel } = $input.first().json;
const BATCH_SIZE = 20;
const batches = [];

for (let i = 0; i < callIds.length; i += BATCH_SIZE) {
  batches.push({
    json: {
      batchCallIds: callIds.slice(i, i + BATCH_SIZE),
      callMetadata,
      totalCalls,
      reportDate,
      dateRangeLabel,
      batchIndex: Math.floor(i / BATCH_SIZE)
    }
  });
}

return batches;

// Merge extensive call data with basic metadata
// Produce one output item per call
const allItems = $input.all();
const enrichedCalls = [];

let globalMetadata = {};
let reportDate = '';
let dateRangeLabel = '';
let totalCalls = 0;

allItems.forEach(item => {
  const data = item.json;
  globalMetadata = { ...globalMetadata, ...(data.callMetadata || {}) };
  reportDate = data.reportDate || reportDate;
  dateRangeLabel = data.dateRangeLabel || dateRangeLabel;
  totalCalls = data.totalCalls || totalCalls;

  const calls = data.calls || [];
  calls.forEach(call => {
    const callId = call.metaData?.id || call.id;
    const meta = globalMetadata[callId] || {};

    const parties = call.parties || [];
    const externalParticipants = parties.filter(p =>
      p.affiliation === 'External' || p.affiliation === 'EXTERNAL'
    );
    const internalParticipants = parties.filter(p =>
      p.affiliation === 'Internal' || p.affiliation === 'INTERNAL'
    );

    enrichedCalls.push({
      callId,
      title: meta.title || call.metaData?.title || 'Untitled',
      started: meta.started || call.metaData?.started,
      durationMinutes: meta.durationMinutes || Math.round((call.metaData?.duration || 0) / 60),
      url: meta.url || call.metaData?.url || '',
      brief: call.content?.brief || '',
      outline: call.content?.outline || [],
      highlights: call.content?.highlights || [],
      topics: call.content?.topics || [],
      trackers: call.content?.trackers || [],
      hasExternalParticipants: externalParticipants.length > 0,
      externalParticipants: externalParticipants.map(p => ({
        name: p.name || 'Unknown',
        email: p.emailAddress || '',
        title: p.title || '',
        company: p.company || ''
      })),
      internalParticipants: internalParticipants.map(p => ({
        name: p.name || 'Unknown',
        email: p.emailAddress || '',
        title: p.title || ''
      }))
    });
  });
});

// Output each call as a separate item for the classification loop
return enrichedCalls.map(call => ({
  json: {
    ...call,
    reportDate,
    dateRangeLabel,
    totalCalls
  }
}));

// Prepare the classification prompt for Gemini
const call = $input.first().json;

const prompt = `You are classifying a Gong call recording for vFairs, a virtual/hybrid events platform.

CALL DATA:
- Title: ${call.title}
- Duration: ${call.durationMinutes} minutes
- Has External Participants: ${call.hasExternalParticipants}
- External Participants: ${JSON.stringify(call.externalParticipants)}
- Internal Participants: ${JSON.stringify(call.internalParticipants)}
- Brief: ${call.brief}
- Topics: ${JSON.stringify(call.topics)}
- Highlights: ${JSON.stringify(call.highlights?.slice(0, 5))}
- Trackers: ${JSON.stringify(call.trackers)}

CLASSIFICATION RULES:
1. "Sales" - Calls with external participants where topics suggest: demo, pricing, proposal, new business, evaluation, POC, RFP, procurement, contract, new account, discovery call
2. "Customer Success" - Calls with existing clients discussing: onboarding, support, renewal, feature requests, training, QBR, implementation, migration, upgrade, account review, check-in
3. "Discard" - Internal meetings, interviews, 1:1s with no external participants, recruiting calls, team standups, all-hands, vendor calls

IMPORTANT: If there are NO external participants, classify as "Discard" unless the call title or brief clearly indicates it is a customer-facing call.

Return ONLY a JSON object with this exact structure, no markdown, no extra text:
{"classification": "Sales" or "Customer Success" or "Discard", "confidence": "High" or "Medium" or "Low", "companyName": "<company name of the external party, or Unknown>", "reason": "<one sentence explaining classification>"}`;

const geminiBody = {
  contents: [{
    parts: [{ text: prompt }]
  }],
  generationConfig: {
    temperature: 0.1,
    maxOutputTokens: 200
  }
};

return [{
  json: {
    ...call,
    geminiRequestBody: JSON.stringify(geminiBody)
  }
}];

// Parse Gemini classification response
const data = $input.first().json;
let classification = 'Discard';
let confidence = 'Low';
let companyName = 'Unknown';
let reason = '';

try {
  let responseText = '';

  // Handle Gemini response structure
  if (data.candidates && data.candidates[0]) {
    responseText = data.candidates[0].content?.parts?.[0]?.text || '';
  } else if (data.error) {
    throw new Error(`Gemini API error: ${data.error.message || JSON.stringify(data.error)}`);
  }

  // Strip markdown code blocks if present
  let cleaned = responseText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  const jsonMatch = cleaned.match(/\{[\s\S]*\}/);
  if (jsonMatch) cleaned = jsonMatch[0];

  const result = JSON.parse(cleaned);
  classification = result.classification || 'Discard';
  confidence = result.confidence || 'Low';
  companyName = result.companyName || 'Unknown';
  reason = result.reason || '';
} catch (err) {
  reason = `Classification parse error: ${err.message}`;
}

// Preserve original call data, strip the gemini request body, add classification
const { geminiRequestBody, candidates, ...callData } = data;

return [{
  json: {
    ...callData,
    classification,
    classificationConfidence: confidence,
    companyName,
    classificationReason: reason
  }
}];

// Filter classified calls: keep only Sales and Customer Success
const allCalls = $input.all().map(item => item.json);

const salesCalls = allCalls.filter(c => c.classification === 'Sales');
const csCalls = allCalls.filter(c => c.classification === 'Customer Success');
const discardedCalls = allCalls.filter(c =>
  c.classification !== 'Sales' && c.classification !== 'Customer Success'
);

// Combine Sales + CS for deep extraction
const callsToProcess = [...salesCalls, ...csCalls];

if (callsToProcess.length === 0) {
  // No relevant calls - pass through to report generation with empty data
  return [{
    json: {
      callsToProcess: [],
      salesCount: 0,
      csCount: 0,
      discardedCount: discardedCalls.length,
      totalProcessed: allCalls.length,
      reportDate: allCalls[0]?.reportDate || new Date().toISOString().split('T')[0],
      dateRangeLabel: allCalls[0]?.dateRangeLabel || '',
      skipDeepExtraction: true
    }
  }];
}

// Output each call to process as a separate item
return callsToProcess.map(call => ({
  json: {
    ...call,
    salesCount: salesCalls.length,
    csCount: csCalls.length,
    discardedCount: discardedCalls.length,
    totalProcessed: allCalls.length
  }
}));

// Parse transcript and prepare deep extraction prompt for Gemini
const data = $input.first().json;

// Extract transcript text from Gong response
let transcriptText = '';
try {
  const transcripts = data.callTranscripts || [];
  if (transcripts.length > 0) {
    const segments = transcripts[0].transcript || [];
    transcriptText = segments.map(seg => {
      const speaker = seg.speakerName || seg.speaker || 'Unknown';
      const text = seg.sentences?.map(s => s.text).join(' ') || seg.text || '';
      return `${speaker}: ${text}`;
    }).join('\n');
  }
} catch (err) {
  transcriptText = '[Transcript unavailable]';
}

// Truncate transcript to first 15000 chars to stay within Gemini limits
const truncatedTranscript = transcriptText.substring(0, 15000);

const prompt = `You are analyzing a ${data.classification} call for vFairs (virtual/hybrid events platform).
Extract structured insights from this Gong call recording.

CALL METADATA:
- Title: ${data.title}
- Duration: ${data.durationMinutes} minutes
- Company: ${data.companyName}
- Call Type: ${data.classification}

GONG AI BRIEF:
${data.brief}

GONG HIGHLIGHTS:
${JSON.stringify(data.highlights?.slice(0, 8))}

GONG TOPICS:
${JSON.stringify(data.topics)}

CALL TRANSCRIPT (truncated):
${truncatedTranscript}

Extract the following into a JSON object. Be specific and use direct quotes where relevant.
For fields not applicable or not discussed, use null or empty array.

{
  "callType": "Sales" or "Customer Success",
  "companyName": "<string>",
  "participants": {
    "internal": [{"name": "<string>", "title": "<string>"}],
    "external": [{"name": "<string>", "title": "<string>", "role": "<string>"}]
  },
  "durationMinutes": <number>,
  "personasInvolved": ["<title/role of each external participant>"],
  "painPoints": ["<specific pain point mentioned>"],
  "goalsObjectives": ["<what the prospect/customer wants to achieve>"],
  "challenges": ["<obstacles or concerns raised>"],
  "competitorMentions": ["<competitor name and context>"],
  "featureRequests": ["<specific feature asked for>"],
  "objections": ["<specific objection raised>"],
  "sentiment": "Positive" or "Neutral" or "Negative",
  "grievances": ["<complaints or frustrations expressed>"],
  "notesForMarketing": ["<messaging opportunities, positioning insights, content ideas>"],
  "keyQuotes": ["<1-2 notable direct quotes from the call>"],
  "nextSteps": ["<specific action items or follow-ups agreed>"],
  "summary": "<3-4 sentence executive summary of this call>"
}

Return ONLY the JSON object, no markdown code blocks, no extra text.`;

const geminiBody = {
  contents: [{
    parts: [{ text: prompt }]
  }],
  generationConfig: {
    temperature: 0.2,
    maxOutputTokens: 1500
  }
};

// Strip transcript and Gong response data to save memory, keep call metadata
const { callTranscripts, candidates, ...callData } = data;

return [{
  json: {
    ...callData,
    hasTranscript: transcriptText.length > 0,
    geminiExtractionBody: JSON.stringify(geminiBody)
  }
}];

// Parse Gemini deep extraction response and merge with call data
const data = $input.first().json;
let extraction = null;

try {
  let responseText = '';

  if (data.candidates && data.candidates[0]) {
    responseText = data.candidates[0].content?.parts?.[0]?.text || '';
  } else if (data.error) {
    throw new Error(`Gemini API error: ${data.error.message || JSON.stringify(data.error)}`);
  }

  // Strip markdown code blocks
  let cleaned = responseText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  const jsonMatch = cleaned.match(/\{[\s\S]*\}/);
  if (jsonMatch) cleaned = jsonMatch[0];

  extraction = JSON.parse(cleaned);
} catch (err) {
  // Fallback: use Gong's brief as the summary
  extraction = {
    callType: data.classification || 'Unknown',
    companyName: data.companyName || 'Unknown',
    participants: { internal: [], external: [] },
    durationMinutes: data.durationMinutes || 0,
    personasInvolved: [],
    painPoints: [],
    goalsObjectives: [],
    challenges: [],
    competitorMentions: [],
    featureRequests: [],
    objections: [],
    sentiment: 'Neutral',
    grievances: [],
    notesForMarketing: [],
    keyQuotes: [],
    nextSteps: [],
    summary: data.brief || `[Extraction failed: ${err.message}]`
  };
}

// Clean up: strip Gemini response data, keep extraction + metadata
const { geminiExtractionBody, candidates, ...callData } = data;

return [{
  json: {
    callId: callData.callId,
    title: callData.title,
    started: callData.started,
    url: callData.url,
    classification: callData.classification,
    classificationConfidence: callData.classificationConfidence,
    reportDate: callData.reportDate,
    dateRangeLabel: callData.dateRangeLabel,
    salesCount: callData.salesCount,
    csCount: callData.csCount,
    discardedCount: callData.discardedCount,
    totalProcessed: callData.totalProcessed,
    extraction
  }
}];

// Collect all extracted calls and prepare for weekly trends aggregation
const allCalls = $input.all().map(item => item.json);

const salesCalls = allCalls.filter(c => c.classification === 'Sales');
const csCalls = allCalls.filter(c => c.classification === 'Customer Success');

// Prepare a compact version for the trends aggregation prompt
const compactCalls = allCalls.map(c => ({
  type: c.classification,
  company: c.extraction?.companyName || 'Unknown',
  summary: c.extraction?.summary || '',
  painPoints: c.extraction?.painPoints || [],
  goalsObjectives: c.extraction?.goalsObjectives || [],
  challenges: c.extraction?.challenges || [],
  competitorMentions: c.extraction?.competitorMentions || [],
  objections: c.extraction?.objections || [],
  featureRequests: c.extraction?.featureRequests || [],
  sentiment: c.extraction?.sentiment || 'Neutral',
  grievances: c.extraction?.grievances || [],
  notesForMarketing: c.extraction?.notesForMarketing || []
}));

return [{
  json: {
    salesCalls,
    csCalls,
    compactCalls,
    salesCount: salesCalls.length,
    csCount: csCalls.length,
    discardedCount: allCalls[0]?.discardedCount || 0,
    totalProcessed: allCalls[0]?.totalProcessed || 0,
    reportDate: allCalls[0]?.reportDate || new Date().toISOString().split('T')[0],
    dateRangeLabel: allCalls[0]?.dateRangeLabel || ''
  }
}];

// Prepare the weekly trends aggregation prompt for Gemini
const data = $input.first().json;

const prompt = `You are analyzing a week's worth of Gong call data for vFairs, a virtual/hybrid events platform growing from $18.5M to $30M ARR.

Analyze these ${data.compactCalls.length} call extractions and produce a weekly trends report.

CALLS THIS WEEK:
${JSON.stringify(data.compactCalls, null, 2)}

Produce a JSON object with these sections. Be specific — reference company names and concrete details, not generic observations.

{
  "weeklyTrends": {
    "topPainPoints": ["<top 3-5 recurring pain points across calls with company references>"],
    "topCompetitors": ["<competitors mentioned with which companies mentioned them>"],
    "emergingThemes": ["<new topics or themes appearing this week>"],
    "sentimentOverview": "<overall sentiment summary across calls>",
    "dealHealthIndicators": ["<signals about pipeline health, hot deals, at-risk deals>"]
  },
  "marketingSignals": {
    "messagingOpportunities": ["<positioning insights for marketing based on what resonated>"],
    "contentIdeas": ["<blog/social content ideas drawn from call themes>"],
    "competitivePositioning": ["<how to differentiate from mentioned competitors>"],
    "objectionPatterns": ["<common objections marketing should address in content/collateral>"],
    "customerSuccessStories": ["<potential case study or testimonial candidates>"]
  }
}

Return ONLY the JSON object, no markdown code blocks, no extra text.`;

const geminiBody = {
  contents: [{
    parts: [{ text: prompt }]
  }],
  generationConfig: {
    temperature: 0.3,
    maxOutputTokens: 2000
  }
};

return [{
  json: {
    ...data,
    geminiTrendsBody: JSON.stringify(geminiBody)
  }
}];

// Parse trends response and generate the final markdown report
const data = $input.first().json;

// Parse trends from Gemini
let trends = { weeklyTrends: {}, marketingSignals: {} };
try {
  let responseText = '';
  if (data.candidates && data.candidates[0]) {
    responseText = data.candidates[0].content?.parts?.[0]?.text || '';
  }
  let cleaned = responseText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  const jsonMatch = cleaned.match(/\{[\s\S]*\}/);
  if (jsonMatch) cleaned = jsonMatch[0];
  trends = JSON.parse(cleaned);
} catch (err) {
  trends = {
    weeklyTrends: { topPainPoints: ['[Trend analysis unavailable]'] },
    marketingSignals: { messagingOpportunities: ['[Analysis unavailable]'] }
  };
}

const wt = trends.weeklyTrends || {};
const ms = trends.marketingSignals || {};

// Get call data (strip Gemini response fields)
const salesCalls = data.salesCalls || [];
const csCalls = data.csCalls || [];

// Helper: format a list with -> bullets
function bulletList(items) {
  if (!items || items.length === 0) return '  -> None noted\n';
  return items.map(item => `  -> ${item}`).join('\n') + '\n';
}

// Helper: format a single call section
function formatCall(call, index) {
  const ext = call.extraction || {};
  let section = '';
  section += `### ${index + 1}. ${ext.companyName || call.title || 'Unknown Company'}\n\n`;
  section += `**Duration:** ${ext.durationMinutes || call.durationMinutes || '?'} min | **Sentiment:** ${ext.sentiment || 'Unknown'}\n\n`;
  section += `**Summary:** ${ext.summary || call.brief || 'No summary available.'}\n\n`;

  // Participants
  const extParticipants = ext.participants?.external || [];
  if (extParticipants.length > 0) {
    section += `**External Participants:**\n`;
    extParticipants.forEach(p => {
      section += `  -> ${p.name || 'Unknown'}${p.title ? ' (' + p.title + ')' : ''}${p.role ? ' - ' + p.role : ''}\n`;
    });
    section += `\n`;
  }

  // Personas
  if (ext.personasInvolved?.length) {
    section += `**Personas:** ${ext.personasInvolved.join(', ')}\n\n`;
  }

  // Pain Points
  if (ext.painPoints?.length) {
    section += `**Pain Points:**\n${bulletList(ext.painPoints)}\n`;
  }

  // Goals / Objectives
  if (ext.goalsObjectives?.length) {
    section += `**Goals & Objectives:**\n${bulletList(ext.goalsObjectives)}\n`;
  }

  // Challenges
  if (ext.challenges?.length) {
    section += `**Challenges:**\n${bulletList(ext.challenges)}\n`;
  }

  // Objections (Sales) or Feature Requests (CS)
  if (ext.callType === 'Sales' && ext.objections?.length) {
    section += `**Objections:**\n${bulletList(ext.objections)}\n`;
  }
  if (ext.callType === 'Customer Success' && ext.featureRequests?.length) {
    section += `**Feature Requests:**\n${bulletList(ext.featureRequests)}\n`;
  }

  // Competitor Mentions
  if (ext.competitorMentions?.length) {
    section += `**Competitor Mentions:**\n${bulletList(ext.competitorMentions)}\n`;
  }

  // Grievances
  if (ext.grievances?.length) {
    section += `**Grievances:**\n${bulletList(ext.grievances)}\n`;
  }

  // Key Quotes
  if (ext.keyQuotes?.length) {
    section += `**Key Quotes:**\n`;
    ext.keyQuotes.forEach(q => {
      section += `  > "${q}"\n\n`;
    });
  }

  // Next Steps
  if (ext.nextSteps?.length) {
    section += `**Next Steps:**\n${bulletList(ext.nextSteps)}\n`;
  }

  // Notes for Marketing
  if (ext.notesForMarketing?.length) {
    section += `**Notes for Marketing:**\n${bulletList(ext.notesForMarketing)}\n`;
  }

  section += `---\n\n`;
  return section;
}

// === BUILD THE MARKDOWN REPORT ===
let md = '';

// Header
md += `# Gong Weekly Call Digest\n\n`;
md += `**Period:** ${data.dateRangeLabel}\n`;
md += `**Generated:** ${new Date().toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })}\n\n`;
md += `---\n\n`;

// Summary Table
md += `## Summary\n\n`;
md += `| Metric | Count |\n`;
md += `|--------|-------|\n`;
md += `| Total Calls Reviewed | ${data.totalProcessed || 0} |\n`;
md += `| Sales Calls | ${data.salesCount || 0} |\n`;
md += `| Customer Success Calls | ${data.csCount || 0} |\n`;
md += `| Discarded (Internal/Other) | ${data.discardedCount || 0} |\n\n`;

// Sales Calls Section
md += `---\n\n## Sales Calls\n\n`;
if (salesCalls.length === 0) {
  md += `_No sales calls this week._\n\n`;
} else {
  salesCalls.forEach((call, i) => {
    md += formatCall(call, i);
  });
}

// CS Calls Section
md += `## Customer Success Calls\n\n`;
if (csCalls.length === 0) {
  md += `_No customer success calls this week._\n\n`;
} else {
  csCalls.forEach((call, i) => {
    md += formatCall(call, i);
  });
}

// Weekly Trends
md += `## Weekly Trends\n\n`;
if (wt.topPainPoints?.length) {
  md += `**Top Pain Points Across Calls:**\n${bulletList(wt.topPainPoints)}\n`;
}
if (wt.topCompetitors?.length) {
  md += `**Top Competitors Mentioned:**\n${bulletList(wt.topCompetitors)}\n`;
}
if (wt.emergingThemes?.length) {
  md += `**Emerging Themes:**\n${bulletList(wt.emergingThemes)}\n`;
}
if (wt.sentimentOverview) {
  md += `**Sentiment Overview:** ${wt.sentimentOverview}\n\n`;
}
if (wt.dealHealthIndicators?.length) {
  md += `**Deal Health Indicators:**\n${bulletList(wt.dealHealthIndicators)}\n`;
}

// Marketing Signals
md += `---\n\n## Marketing Signals\n\n`;
if (ms.messagingOpportunities?.length) {
  md += `**Messaging Opportunities:**\n${bulletList(ms.messagingOpportunities)}\n`;
}
if (ms.contentIdeas?.length) {
  md += `**Content Ideas:**\n${bulletList(ms.contentIdeas)}\n`;
}
if (ms.competitivePositioning?.length) {
  md += `**Competitive Positioning:**\n${bulletList(ms.competitivePositioning)}\n`;
}
if (ms.objectionPatterns?.length) {
  md += `**Objection Patterns to Address:**\n${bulletList(ms.objectionPatterns)}\n`;
}
if (ms.customerSuccessStories?.length) {
  md += `**Case Study Candidates:**\n${bulletList(ms.customerSuccessStories)}\n`;
}

md += `---\n\n*Generated by Gong Weekly Digest workflow*\n`;

const filename = `gong-weekly-${data.reportDate}.md`;

return [{
  json: {
    markdownContent: md,
    filename,
    dateRangeLabel: data.dateRangeLabel,
    salesCount: data.salesCount,
    csCount: data.csCount,
    discardedCount: data.discardedCount
  }
}];

// Convert markdown string to binary data for Google Drive upload
const data = $input.first().json;

return [{
  json: data,
  binary: {
    data: {
      data: Buffer.from(data.markdownContent, 'utf8').toString('base64'),
      mimeType: 'text/markdown',
      fileName: data.filename,
      fileExtension: 'md'
    }
  }
}];

