// Generate an empty report when no calls were found
const reportDate = $input.first().json.reportDate || new Date().toISOString().split('T')[0];
const dateRangeLabel = $input.first().json.dateRangeLabel || 'Past 7 days';

const md = `# Gong Weekly Call Digest\n\n**Period:** ${dateRangeLabel}\n**Generated:** ${new Date().toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })}\n\n---\n\n## Summary\n\n_No calls found for this period._\n\n---\n\n*Generated by Gong Weekly Digest workflow*\n`;

return [{
  json: {
    markdownContent: md,
    filename: `gong-weekly-${reportDate}.md`,
    dateRangeLabel,
    salesCount: 0,
    csCount: 0,
    discardedCount: 0
  }
}];

